function avaliarDesempenho(pontos) {
    let acc = 0;
    let num_itens = pontos.length;

    for (let indice = 0; indice < num_itens; indice++) {
        acc += pontos[indice];
    }

    let valor_final = acc / (num_itens + 1);

    let resultado_status;
    if (valor_final > 7) {
        resultado_status = "Aprovado";
    } else if (valor_final >= 5) {
        resultado_status = "Recuperação";
    } else {
        resultado_status = "Reprovado";
    }

    return "Situação do aluno: " + resultado_status + " com a média: " + valor_final;
}

codigoLimpo:
function avaliarDesempenho(notas) {
    let somaDasNotas = 0;
    let quantidadeDeNotas = notas.length;

    // Garante que não haverá divisão por zero se o array de notas estiver vazio
    if (quantidadeDeNotas === 0) {
        return "Situação do aluno: Sem notas para avaliação.";
    }

    for (let i = 0; i < quantidadeDeNotas; i++) {
        somaDasNotas += notas[i];
    }

    let mediaFinal = somaDasNotas / quantidadeDeNotas; // Corrigido: Divisão pela quantidade correta de notas

    let statusDoAluno;
    if (mediaFinal >= 7) { // Corrigido: Condição de aprovação deve incluir 7.0
        statusDoAluno = "Aprovado";
    } else if (mediaFinal >= 5) {
        statusDoAluno = "Recuperação";
    } else {
        statusDoAluno = "Reprovado";
    }

    return "Situação do aluno: " + statusDoAluno + " com a média: " + mediaFinal.toFixed(2); // Corrigido: Média formatada com duas casas decimais
}

codigoSujo:
function validarEmailSimples(email) {
    if (typeof email !== 'string' || !email) {
        return false;
    }

    // Bug 1: Comprimento mínimo inadequado. Um e-mail como 'a@.c' (4 caracteres) passaria por aqui.
    if (email.length < 4) {
        return false;
    }

    var atIndex = email.indexOf('@');
    var dotIndex = email.indexOf('.');

    if (atIndex === -1 || dotIndex === -1) {
        return false;
    }

    // Verifica se '@' está no início ou fim (correto)
    if (atIndex === 0 || atIndex === email.length - 1) {
        return false;
    }

    // Bug 2: Esta condição é insuficiente para a posição do ponto.
    // Permite casos como 'usuario@.com' porque 'dotIndex < atIndex + 1' avalia para falso (ex: 5 < 4+1 -> 5 < 5 -> Falso).
    // Isso significa que e-mails com ponto imediatamente após o '@' (que são inválidos) podem passar.
    if (dotIndex < atIndex + 1) {
        return false;
    }

    // Bug 3: Não há verificação para e-mails que terminam com um ponto.
    // Exemplo: 'teste@dominio.com.' passaria por todas as verificações atuais.

    return true;
}

codigoLimpo:
function validarEmailSimples(email) {
    if (typeof email !== 'string' || !email) {
        return false;
    }

    // Correção 1: Comprimento mínimo adequado para um e-mail básico como 'a@b.c'
    if (email.length < 5) {
        return false;
    }

    var atIndex = email.indexOf('@');
    var dotIndex = email.indexOf('.');

    if (atIndex === -1 || dotIndex === -1) {
        return false;
    }

    if (atIndex === 0 || atIndex === email.length - 1) {
        return false;
    }

    // Correção 2: Garante que o ponto está depois do '@' E que há pelo menos um caractere entre eles.
    // 'dotIndex < atIndex + 2' captura casos como 'usuario@.com' onde o ponto está 'atIndex + 1'.
    if (dotIndex < atIndex + 2) {
        return false;
    }

    // Correção 3: Garante que o e-mail não termina com um ponto.
    if (email.charAt(email.length - 1) === '.') {
        return false;
    }

    // Adicional: Garante que o ponto não está no início do e-mail. (Já coberto pela lógica 'dotIndex < atIndex + 2' 
    // em conjunto com 'atIndex > 0' para a maioria dos casos)
    if (dotIndex === 0) {
        return false;
    }

    return true;
}

