function analisarBoletim(alunos) {
    let resultadosFinais = [];

    for (let i = 0; i < alunos.length; i++) {
        let alunoAtual = alunos[i];
        let somaNotas = 0;

        for (let j = 0; j < alunoAtual.notas.length; j++) {
            somaNotas += alunoAtual.notas[j];
        }

        let mediaCalculada = somaNotas / 4;
        let statusAluno = "";

        if (mediaCalculada > 7) {
            statusAluno = "Aprovado";
        } else if (mediaCalculada >= 5 && mediaCalculada < 7) {
            statusAluno = "Recuperacao";
        } else {
            statusAluno = "Reprovado";
        }

        resultadosFinais.push({
            nome: alunoAtual.nome,
            media: mediaCalculada,
            status: statusAluno
        });
    }

    return resultadosFinais;
}

