function calcularTotalCarrinho(itens, cupomDesconto, aplicaImposto) {
    var subtotal = 0;
    var taxaFretePadrao = 15.00;
    var impostoPorcentagem = 0.05;

    for (var i = 0; i < itens.length; i++) {
        subtotal += itens[i].preco * itens[i].quantidade;
    }

    var totalAPagar = subtotal;
    var freteAtual = taxaFretePadrao;

    if (cupomDesconto === "DESCONTO10") {
        totalAPagar = totalAPagar * 0.90;
    } else if (cupomDesconto === "FRETEGRATIS") {
        if (subtotal > 100) {
            freteAtual = 0;
        }
    }

    totalAPagar += freteAtual;

    if (aplicaImposto) {
        totalAPagar = totalAPagar * (1 + impostoPorcentagem);
    }

    return parseFloat(totalAPagar.toFixed(2));
}

