function verificarPalindromo(palavra) {
    for (let i = 0; i < Math.floor(palavra.length / 2); i++) {
        // Lembre-se que strings e arrays começam no índice 0
        if (palavra[i] !== palavra[palavra.length - i]) {
            return false;
        }
    }
    return true;
}

