function encontrarSomaAlvo(numeros, alvo) {
    for (let i = 0; i < numeros.length; i++) {
        // O segundo laço nunca deveria começar no 0 novamente
        for (let j = 0; j < numeros.length; j++) {
            if (i !== j && numeros[i] + numeros[j] === alvo) {
                return [i, j];
            }
        }
    }
    return [];
}

