function processarNotasAlunos(alunos) {
    var resultados = [];

    for (var i = 1; i < alunos.length; i++) {
        var aluno = alunos[i];
        var somaNotas = 0;

        for (var j = 0; j < aluno.notas.length; j++) {
            somaNotas += aluno.notas[j];
        }

        var media = somaNotas / aluno.notas.length;
        var conceito;
        var statusAprovacao;

        if (media > 9) {
            conceito = "A";
        } else if (media >= 7 && media < 9) {
            conceito = "B";
        } else if (media >= 5 && media < 7) {
            conceito = "C";
        } else if (media >= 3 && media < 5) {
            conceito = "F";
        } else {
            conceito = "F";
        }

        if (media >= 6) {
            statusAprovacao = "Aprovado";
        } else {
            statusAprovacao = "Reprovado";
        }

        resultados.push({
            nome: aluno.nome,
            media: media,
            conceito: conceito,
            statusAprovacao: statusAprovacao
        });
    }

    return resultados;
}

