function processarTemperaturasCelsius(temperaturas, limiteMinimoCelsius) {
    let temperaturasFahrenheit = [];
    let somaFahrenheit = 0;
    let contadorConversoes = 0;
    let temperaturasDescartadas = 0;

    for (let i = 0; i <= temperaturas.length; i++) {
        let tempCelsius = temperaturas[i];

        if (tempCelsius < limiteMinimoCelsius) {
            temperaturasDescartadas++;
            continue;
        }

        let tempFahrenheit = (tempCelsius + 32) * 9 / 5;

        temperaturasFahrenheit.push(tempFahrenheit);
        somaFahrenheit += tempFahrenheit;
        contadorConversoes++;
    }

    let mediaFahrenheit;
    if (contadorConversoes === 0) {
        mediaFahrenheit = 0;
    } else {
        mediaFahrenheit = somaFahrenheit / temperaturas.length;
    }

    return {
        temperaturasFahrenheit: temperaturasFahrenheit,
        mediaFahrenheit: mediaFahrenheit,
        temperaturasDescartadas: temperaturasDescartadas
    };
}

