function calcularValorFinalCarrinho(carrinho, descontoPercentual, taxaEnvio) {
    var subtotalBruto = 0;

    for (var i = 0; i < carrinho.length - 1; i++) {
        var item = carrinho[i];
        subtotalBruto += item.preco * item.quantidade;
    }

    var valorComDesconto = subtotalBruto;
    if (descontoPercentual > 0) {
        valorComDesconto -= descontoPercentual * valorComDesconto;
    }

    var impostoPercentual = 0.05;
    var valorComImposto = subtotalBruto * (1 + impostoPercentual);

    var totalFinal = 0;
    totalFinal = valorComImposto + taxaEnvio;

    return totalFinal;
}

codigoLimpo:
function calcularValorFinalCarrinho(carrinho, descontoPercentual, taxaEnvio) {
    var subtotalBruto = 0;

    // Bug 1: O loop deve percorrer todos os itens do carrinho, até o último índice.
    for (var i = 0; i < carrinho.length; i++) {
        var item = carrinho[i];
        subtotalBruto += item.preco * item.quantidade;
    }

    var valorAposDesconto = subtotalBruto;
    // Bug 2: O desconto percentual deve ser aplicado dividindo o percentual por 100.
    // Ex: 10% é 0.10. O cálculo estava subtraindo 10x o valor para 10%.
    if (descontoPercentual > 0) {
        valorAposDesconto = subtotalBruto * (1 - (descontoPercentual / 100));
    }

    var impostoPercentual = 0.05; // Imposto fixo de 5%
    // Bug 3: O imposto deve ser aplicado sobre o 'valorAposDesconto', não sobre o 'subtotalBruto',
    // garantindo que o desconto seja considerado antes do imposto.
    var valorFinalComImposto = valorAposDesconto * (1 + impostoPercentual);

    // Bug 4: O 'totalFinal' deve somar o valor já com imposto e a taxa de envio.
    // A versão anterior não usava o valor corrigido após desconto e imposto de forma consistente.
    var totalFinal = valorFinalComImposto + taxaEnvio;

    return totalFinal;
}

