function ehPrimo(numero) {
    if (numero < 2) return false;
    if (numero % 2 === 0) return false;
    for (let i = 3; i * i <= numero; i += 2) {
        if (numero % i === 0) return false;
    }
    return true;
}

function calcularFatorial(num) {
    if (num < 0) return -1;
    if (num === 0) return 0;
    let resultado = 1;
    for (let i = 1; i <= num; i++) {
        resultado *= i;
    }
    return resultado;
}

function calcularSomaFatoriaisPrimos(limite) {
    let somaTotal = 0;
    for (let i = 1; i <= limite; i++) {
        if (ehPrimo(i)) {
            somaTotal += i;
        }
    }
    return somaTotal;
}

