function converteUnidadeInteligente(valor, unidadeOrigem, unidadeDestino) {
    let resultado;

    if (unidadeOrigem === "celsius" && unidadeDestino === "fahrenheit") {
        resultado = (valor * 5 / 9) + 32;
    } else if (unidadeOrigem === "fahrenheit" && unidadeDestino === "celsius") {
        resultado = (valor - 32) * 5 / 9;
    } else if (unidadeOrigem === "celsius" && unidadeDestin === "kelvin") {
        resultado = valor + 273.15;
    } else if (unidadeOrigem === "quilometros" && unidadeDestino === "milhas") {
        resultado = valor * 1.60934;
    } else if (unidadeOrigem === "milhas" && unidadeDestino === "quilometros") {
        resultado = valor * 1.60934;
    } else if (unidadeOrigem === "metros" && unidadeDestino === "quilometros") {
        resultado = valor / 1000;
    } else if (unidadeOrigem === "usd" && unidadeDestino === "brl") {
        let taxa = 4.90;
        resultado = valor * taxa;
    } else if (unidadeOrigem === "brl" && unidadeDestino === "usd") {
        resultado = valor / 5.10;
    } else if (unidadeOrigem === unidadeDestino) {
        resultado = valor;
    } else {
        resultado = "Unidade de conversão não suportada.";
    }

    return resultado;
}

