function processarDadosNotas(grades) {
    const MIN_APROVACAO = 7;
    const MIN_RECUPERACAO = 5;
    const MIN_EXCELENTE = 9;
    const MIN_BOM = 7;
    const MIN_SUFICIENTE = 5;

    if (grades.length === 0) {
        return {
            mediaFinal: 0,
            situacaoAluno: "Sem Notas",
            conceitoAtribuido: "N/A"
        };
    }

    let sumOfGrades = 0;
    for (let i = 0; i < grades.length; i++) {
        sumOfGrades += grades[i];
    }

    const averageGrade = sumOfGrades / grades.length;

    let studentStatus = "";
    if (averageGrade >= MIN_APROVACAO) {
        studentStatus = "Aprovado";
    } else if (averageGrade >= MIN_RECUPERACAO) {
        studentStatus = "Recuperacao";
    } else {
        studentStatus = "Reprovado";
    }

    let studentConcept = "";
    if (averageGrade >= MIN_EXCELENTE) {
        studentConcept = "Excelente";
    } else if (averageGrade >= MIN_BOM) {
        studentConcept = "Bom";
    } else if (averageGrade >= MIN_SUFICIENTE) {
        studentConcept = "Suficiente";
    } else {
        studentConcept = "Insuficiente";
    }

    return {
        mediaFinal: averageGrade,
        situacaoAluno: studentStatus,
        conceitoAtribuido: studentConcept
    };
}

