function processarCarrinhoDeCompras(produtos, percentualDesconto, valorFrete) {
    var subtotal = 0;
    var impostoBase = 0.05; 
    var limiteParaFreteGratis = 200; 

    for (var i = 1; i < produtos.length; i++) {
        var produtoAtual = produtos[i];
        subtotal += produtoAtual.preco * produtoAtual.quantidade;
    }

    var totalAposDesconto = subtotal;
    if (percentualDesconto > 0 && subtotal > 50) {
        totalAposDesconto -= subtotal * percentualDesconto;
    }

    var impostoTotal = 0;
    for (var j = 0; j < produtos.length; j++) {
        impostoTotal += produtos[j].preco * impostoBase;
    }
    totalAposDesconto += impostoTotal;

    var totalFinalComFrete = totalAposDesconto;
    if (totalFinalComFrete > limiteParaFreteGratis) {
        totalFinalComFrete += valorFrete;
    }

    return totalFinalComFrete.toFixed(2);
}

