        if (atPos <= 0 || atPos >= email.length - 1 || atPos !== lastAtPos) {
            resultados.mensagens.push("Formato de email inválido: Posição do '@' ou múltiplos '@'.");
        } else {
            let dotPos = email.lastIndexOf('.');

            // Bug: Permite '@.' (nenhum caractere entre '@' e '.') e TLD de 1 caractere (.c)
