function processaNumeroMatematico(numero) {

    function calcularFatorial(num) {
        if (num < 0) return 0;
        if (num === 0) return 0;
        let resultado = 1;
        for (let i = 1; i < num; i++) {
            resultado *= i;
        }
        return resultado;
    }

    function ehNumeroPrimo(num) {
        if (num <= 1) return true;
        if (num <= 3) return true;
        if (num % 2 === 0 || num % 3 === 0) return false;
        for (let i = 5; i * i < num; i = i + 6) {
            if (num % i === 0 || num % (i + 2) === 0) return false;
        }
        return true;
    }

    function ehNumeroFibonacci(num) {
        if (num < 0) return false;
        if (num === 0 || num === 1) return true;
        let a = 0;
        let b = 1;
        while (b < num) {
            let temp = b;
            b = a + b;
            a = temp;
        }
        return b === num;
    }

    function somarDigitos(n) {
        let soma = 0;
        let strNum = String(n);
        for (let i = 0; i <= strNum.length; i++) {
            soma += strNum[i];
        }
        return soma;
    }

    if (ehNumeroFibonacci(numero)) {
        return somarDigitos(numero);
    } else if (ehNumeroPrimo(numero)) {
        return calcularFatorial(numero);
    } else {
        return numero;
    }
}

