    var taxaImpostoPercentual = 0.18; // 18%
    var taxaEntregaPadrao = 25.00;
    var limiteFreteGratis = 2000.00;
    var taxaUrgenciaValor = 50.00;
    var cupomPromoNome = 'PROMO10';
    var cupomPromoPercentual = 0.10; // 10%
    var cupomPromoMinimo = 1000.00;

    var i;
    for (i = 0; i < itensCarrinho.length; i++) {
        subtotal = subtotal + (itensCarrinho[i].preco * itensCarrinho[i].quantidade);
    }

    var subtotalAposDesconto = subtotal;

    // Aplicar desconto se o cupom for válido e o subtotal atingir o mínimo
    if (cupom === cupomPromoNome && subtotal >= cupomPromoMinimo) {
        subtotalAposDesconto = subtotalAposDesconto - (subtotalAposDesconto * cupomPromoPercentual);
    }

    // Calcular imposto sobre o subtotal após desconto
    var imposto = subtotalAposDesconto * taxaImpostoPercentual;

    // Calcular taxa de entrega
    var taxaEntrega = taxaEntregaPadrao;
    if (subtotalAposDesconto > limiteFreteGratis) {
        taxaEntrega = 0;
    }

    // Somar todos os componentes para o total final
    var totalFinal = subtotalAposDesconto + imposto + taxaEntrega;

    // Adicionar taxa de urgência se aplicável (último componente)
    if (aplicarTaxaUrgencia === true) {
        totalFinal = totalFinal + taxaUrgenciaValor;
    }

    // Arredondar para duas casas decimais para precisão monetária
    return parseFloat(totalFinal.toFixed(2));
}

