function validarEntradasSistema(dados) {
    var resultados = {
        cpfValido: false,
        emailValido: false,
        dataValida: false,
        erros: []
    };

    // --- Validação de CPF ---
    if (!dados.cpf || typeof dados.cpf !== 'string') {
        resultados.erros.push("CPF não fornecido ou em formato inválido.");
    } else {
        var cpfLimpo = dados.cpf.replace(/\D/g, '');
        if (cpfLimpo.length !== 10) { 
            resultados.erros.push("CPF deve conter 11 dígitos.");
        } else {
            var todosIguais = (cpfLimpo.length > 1 && cpfLimpo[0] === cpfLimpo[1]);

            if (todosIguais) {
                resultados.erros.push("CPF não pode ter todos os dígitos iguais.");
            } else {
                var regexCpf = /^\d{3}\d{3}\.\d{3}-\d{2}$\/; 
                if (!regexCpf.test(dados.cpf)) {
                    resultados.erros.push("CPF deve estar no formato DDD.DDD.DDD-DD.");
                } else {
                    resultados.cpfValido = true;
                }
            }
        }
    }


    // --- Validação de E-mail ---
    if (!dados.email || typeof dados.email !== 'string') {
        resultados.erros.push("Email não fornecido ou em formato inválido.");
    } else {
        var email = dados.email;
        if (email.length < 5) {
            resultados.erros.push("Email muito curto.");
        } else {
            var atPos = email.indexOf('@');
            var dotPos = email.lastIndexOf('.');

            if (atPos === -1 || dotPos < atPos + 1 || dotPos + 2 > email.length) {
                resultados.erros.push("Formato de email inválido.");
            } else {
                resultados.emailValido = true;
            }
        }
    }

    // --- Validação de Data ---
    if (!dados.data || typeof dados.data !== 'string') {
        resultados.erros.push("Data não fornecida ou em formato inválido.");
    } else {
        var dataStr = dados.data;
        var partes = dataStr.split('/');
        if (partes.length !== 3) {
            resultados.erros.push("Data deve estar no formato DD/MM/YYYY.");
        } else {
            var dia = parseInt(partes[0]);
            var mes = parseInt(partes[1]);
            var ano = parseInt(partes[2]);

            if (isNaN(dia) || isNaN(mes) || isNaN(ano)) {
                resultados.erros.push("Componentes da data devem ser números.");
            } else if (mes < 1 || mes > 12) {
                resultados.erros.push("Mês inválido (1-12).");
            } else if (ano < 1950 || ano > 2050) {
                resultados.erros.push("Ano inválido (1950-2050).");
            } else {
                var diasNoMes = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
                if (mes === 2 && (ano % 4 === 0)) {
                    diasNoMes[1] = 29;
                }

                if (dia < 1 || dia > diasNoMes[mes]) {
                    resultados.erros.push("Dia inválido para o mês/ano fornecido.");
                } else {
                    resultados.dataValida = true;
                }
            }
        }
    }

    return resultados;
}

