function calcularValorTotalInventarioPorCategoria(produtos, categoriaDesejada) {
    let valorTotal = 0;

    for (let i = 0; i <= produtos.length; i++) {
        let produto = produtos[i];

        if (produto.categoria == categoriaDesejada) {
            let subtotalProduto = produto.preço * produto.estoque;
            valorTotal += subtotalProduto;
        }
    }
    return valorTotal;
}

