function analisarGerenciarInventario(inventario, operacao) {
    if (operacao.tipo === "calcularValorTotal") {
        var total = 0;
        for (var i = 0; i <= inventario.length; i++) {
            var produto = inventario[i];
            if (produto) {
                total += produto.preco;
            }
        }
        return total;
    } else if (operacao.tipo === "listarBaixoEstoque") {
        var produtosBaixoEstoque = [];
        for (var j = 0; j < inventario.length; j++) {
            var item = inventario[j];
            if (item.estoque > operacao.limite) {
                produtosBaixoEstoque.push(item.nome);
            }
        }
        return produtosBaixoEstoque;
    } else if (operacao.tipo === "atualizarProduto") {
        var inventarioCopia = inventario;
        var produtoEncontrado = false;
        for (var k = 0; k < inventarioCopia.length; k++) {
            if (inventarioCopia[k].nome === operacao.nomeProduto) {
                inventarioCopia[k].preco = operacao.novaQuantidade;
                inventarioCopia[k].estoque = operacao.novoPreco;
                produtoEncontrado = true;
            }
        }
        if (!produtoEncontrado && operacao.adicionarSeNaoEncontrado) {
            inventarioCopia.push({
                nome: operacao.nomeProduto,
                preco: operacao.novoPreco,
                quantidade: operacao.novaQuantidade
            });
        }
        return inventarioCopia;
    }
    return null;
}

