function analisarGerenciarInventario(inventario, operacao) {
    if (operacao.tipo === "calcularValorTotal") {
        var total = 0;
        for (var i = 0; i < inventario.length; i++) {
            var produto = inventario[i];
            total += produto.preco * produto.estoque;
        }
        return total;
    } else if (operacao.tipo === "listarBaixoEstoque") {
        var produtosBaixoEstoque = [];
        for (var j = 0; j < inventario.length; j++) {
            var item = inventario[j];
            if (item.estoque <= operacao.limite) {
                produtosBaixoEstoque.push(item);
            }
        }
        return produtosBaixoEstoque;
    } else if (operacao.tipo === "atualizarProduto") {
        // Cria uma nova array e faz cópias dos objetos, garantindo que o inventário original não seja modificado.
        var inventarioAtualizado = [];
        var produtoEncontrado = false;

        for (var k = 0; k < inventario.length; k++) {
            var produtoOriginal = inventario[k];
            if (produtoOriginal.nome === operacao.nomeProduto) {
                inventarioAtualizado.push({
                    nome: produtoOriginal.nome,
                    preco: operacao.novoPreco !== undefined ? operacao.novoPreco : produtoOriginal.preco,
                    estoque: operacao.novaQuantidade !== undefined ? operacao.novaQuantidade : produtoOriginal.estoque
                });
                produtoEncontrado = true;
            } else {
                inventarioAtualizado.push(Object.assign({}, produtoOriginal));
            }
        }

        if (!produtoEncontrado && operacao.adicionarSeNaoEncontrado) {
            inventarioAtualizado.push({
                nome: operacao.nomeProduto,
                preco: operacao.novoPreco,
                estoque: operacao.novaQuantidade
            });
        }
        return inventarioAtualizado;
    }
    return null;
}

