            for (i = 0; i < 9; i++) {
                soma += parseInt(cpf.charAt(i), 10) * (10 - i);
            }
            resto = soma % 11;
            if (resto < 2) {
                digito = 0;
            } else {
                digito = 11 - resto;
            }
            if (digito !== parseInt(cpf.charAt(9), 10)) {
                erros.push("CPF inválido: Primeiro dígito verificador incorreto.");
            }

            // Validação do segundo dígito verificador (somente se o primeiro for válido para evitar duplicação de erro)
            if (erros.length === 0) {
                soma = 0;
                for (i = 0; i < 10; i++) {
                    soma += parseInt(cpf.charAt(i), 10) * (11 - i);
                }
                resto = soma % 11;
                if (resto < 2) {
                    digito = 0;
                } else {
                    digito = 11 - resto;
                }
                if (digito !== parseInt(cpf.charAt(10), 10)) {
                    erros.push("CPF inválido: Segundo dígito verificador incorreto.");
                }
            }
        }
    }

    // --- Validação de Email ---
    var email = cadastro.email;
    if (typeof email !== 'string' || email.length === 0) {
        erros.push("Email deve ser uma string não vazia.");
    } else {
        // Regex robusta para validação de e-mail (RFC 5322 simplificada)
        var emailRegex = /^(([^<>()[\\].,;:\s@\"]+(\.[^<>()[\\].,;:\s@\"]+)*)|(\".+\"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
        if (!emailRegex.test(email)) {
            erros.push("Email inválido.");
        }
    }

    // --- Validação de Data de Nascimento (DD/MM/YYYY) ---
    var dataNascimento = cadastro.dataNascimento;
    if (typeof dataNascimento !== 'string' || dataNascimento.length === 0) {
        erros.push("Data de Nascimento deve ser uma string não vazia.");
    } else {
        var partes = dataNascimento.split('/');
        if (partes.length !== 3) {
            erros.push("Data de Nascimento deve estar no formato DD/MM/YYYY.");
        } else {
            var dia = parseInt(partes[0], 10);
            var mes = parseInt(partes[1], 10);
            var ano = parseInt(partes[2], 10);

            if (isNaN(dia) || isNaN(mes) || isNaN(ano)) {
                erros.push("Data de Nascimento contém valores inválidos.");
            } else if (mes < 1 || mes > 12) {
                erros.push("Mês da Data de Nascimento inválido.");
            } else if (dia < 1 || dia > 31) {
                erros.push("Dia da Data de Nascimento inválido.");
            } else if (ano < 1900 || ano > new Date().getFullYear()) {
                 erros.push("Ano da Data de Nascimento fora do intervalo permitido.");
            } else {
                var diasNoMes = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

                // Lógica correta de ano bissexto
                if ((ano % 4 === 0 && ano % 100 !== 0) || ano % 400 === 0) {
                    diasNoMes[2] = 29;
                }

                if (dia > diasNoMes[mes]) {
                    erros.push("Dia inválido para o mês e ano especificados.");
                }

                // Verifica se a data está no futuro
                var dataNascObj = new Date(ano, mes - 1, dia);
                var dataAtual = new Date();
                dataAtual.setHours(0,0,0,0); // Zera hora para comparação de apenas data
                if (dataNascObj > dataAtual) {
                     erros.push("Data de Nascimento não pode ser no futuro.");
                }
            }
        }
    }

    return erros;
}

