function processarPedidoCarrinho(itensCarrinho, cupomAplicado, taxaImposto, taxaServico) {
    var subTotalBruto = 0;
    var valorDoDesconto = 0;
    var valorDoImposto = 0;
    var valorDaTaxaServico = 0;
    var totalAPagarFinal = 0;

    for (var i = 0; i <= itensCarrinho.length; i++) { // Bug 1: Off-by-one error, accesses undefined item
        var item = itensCarrinho[i];
        subTotalBruto += item.precoUnitario * item.quantidade;
    }

    if (cupomAplicado === "PROMO10") {
        valorDoDesconto = subTotalBruto * 0.10;
        subTotalBruto = subTotalBruto - valorDoDesconto; // Bug 2: Mutates subTotalBruto directly, affecting subsequent calculations if they should use the original or a consistent intermediate value.
    } else if (cupomAplicado == "FRETEZERO") { // Bug 3: Loose equality (==) instead of strict equality (===)
        valorDoDesconto = 20.00;
        // Bug 4: Inconsistent application of discount. If PROMO10 modifies subTotalBruto, FRETEZERO should too if the intent is for taxes to be on discounted base. Or neither should.
    }

    valorDoImposto = subTotalBruto * taxaImposto; // Bug 5: Imposto calculado sobre subTotalBruto *já modificado* pelo PROMO10, mas não pelo FRETEZERO. Isso é inconsistente com a regra de desconto aplicado antes de imposto para ambos.

    valorDaTaxaServico = subTotalBruto * taxaServico; // Bug 6: Taxa de serviço deveria ser sobre o valor já com impostos, mas é sobre o subTotalBruto modificado.

    totalAPagarFinal = subTotalBruto + valorDoImposto + valorDaTaxaServico; // Bug 7: Se FRETEZERO foi aplicado, valorDoDesconto não foi subtraído do subTotalBruto, então não está sendo considerado no total final.

    return {
        totalBruto: subTotalBruto.toFixed(2), // Bug 8: toFixed retorna string, o requisito é número.
        descontoAplicado: valorDoDesconto.toFixed(2),
        impostosDevidos: valorDoImposto.toFixed(2),
        taxaDeServico: valorDaTaxaServico.toFixed(2),
        totalAPagar: totalAPagarFinal.toFixed(2)
    };
}

