function processarPedidoCarrinho(itensCarrinho, cupomAplicado, taxaImposto, taxaServico) {
    var totalBrutoBase = 0;

    // 1. Calcular total bruto base
    for (var i = 0; i < itensCarrinho.length; i++) {
        var item = itensCarrinho[i];
        totalBrutoBase += item.precoUnitario * item.quantidade;
    }

    var valorDoDesconto = 0;
    // 2. Aplicar descontos
    if (cupomAplicado === "PROMO10") {
        valorDoDesconto = totalBrutoBase * 0.10;
    } else if (cupomAplicado === "FRETEZERO") {
        valorDoDesconto = 20.00;
    }

    var subTotalAposDesconto = totalBrutoBase - valorDoDesconto;

    // 3. Calcular impostos (incidem sobre o valor após desconto)
    var valorDoImposto = subTotalAposDesconto * taxaImposto;

    var subTotalComImposto = subTotalAposDesconto + valorDoImposto;

    // 4. Calcular taxa de serviço (incide sobre o total com impostos)
    var valorDaTaxaServico = subTotalComImposto * taxaServico;

    // 5. Calcular total final a pagar
    var totalAPagarFinal = subTotalComImposto + valorDaTaxaServico;

    // 6. Retornar resultados como números com duas casas decimais
    return {
        totalBruto: Number(totalBrutoBase.toFixed(2)),
        descontoAplicado: Number(valorDoDesconto.toFixed(2)),
        impostosDevidos: Number(valorDoImposto.toFixed(2)),
        taxaDeServico: Number(valorDaTaxaServico.toFixed(2)),
        totalAPagar: Number(totalAPagarFinal.toFixed(2))
    };
}

