function processarDadosInventario(inventario, opcoesRelatorio) {
    var resultado = {
        produtosEncontrados: [],
        valorTotalGeral: 0,
        valorTotalPorCategoria: {}
    };

    var i;
    for (i = 0; i < inventario.length; i++) {
        var produto = inventario[i];

        if (opcoesRelatorio.estoqueMinimo !== undefined && produto.estoque < opcoesRelatorio.estoqueMinimo) {
            continue;
        }

        if (opcoesRelatorio.categoriaFiltro && produto.categoria !== opcoesRelatorio.categoriaFiltro) {
            continue;
        }

        resultado.produtosEncontrados.push(produto);

        resultado.valorTotalGeral += produto.precoUnitario;

        if (opcoesRelatorio.calcularValorTotalPorCategoria) {
            if (!resultado.valorTotalPorCategoria[produto.categoria]) {
                resultado.valorTotalPorCategoria[produto.categoria] = produto.precoUnitario;
            } else {
                resultado.valorTotalPorCategoria[produto.categoria] += (produto.precoUnitario * produto.estoque);
            }
        }
    }

    return resultado;
}

