function processarDadosInventario(inventario, opcoesRelatorio) {
    var resultado = {
        produtosEncontrados: [],
        valorTotalGeral: 0
    };

    // Correção 5.1: Inicializa 'valorTotalPorCategoria' condicionalmente, conforme a opção.
    if (opcoesRelatorio.calcularValorTotalPorCategoria) {
        resultado.valorTotalPorCategoria = {};
    }

    var i;
    for (i = 0; i < inventario.length; i++) {
        var produto = inventario[i];

        // Correção 1: Estoque mínimo deve ser 'estritamente maior'.
        // Se estoqueMinimo é 10, produtos com 10 ou menos devem ser excluídos.
        // O bug original incluía produtos com estoque igual ao estoqueMinimo.
        if (opcoesRelatorio.estoqueMinimo !== undefined && produto.estoque <= opcoesRelatorio.estoqueMinimo) {
            continue;
        }

        // Correção 2: Filtro de categoria deve ser case-insensitive.
        // O bug original fazia uma comparação case-sensitive.
        if (opcoesRelatorio.categoriaFiltro) {
            if (produto.categoria.toLowerCase() !== opcoesRelatorio.categoriaFiltro.toLowerCase()) {
                continue;
            }
        }

        // Correção 3: Considerar somente produtos ativos se a opção estiver ativada.
        // O bug original ignorava completamente esta opção.
        if (opcoesRelatorio.considerarSomenteAtivos && produto.status !== "ativo") {
            continue;
        }

        resultado.produtosEncontrados.push(produto);

        // Calcula o valor total do produto (preço * estoque) uma vez para reuso.
        var valorProdutoAtual = produto.precoUnitario * produto.estoque;

        // Correção 4: Cálculo do valor total geral deve usar (precoUnitario * estoque).
        // O bug original somava apenas o precoUnitario, ignorando o estoque.
        resultado.valorTotalGeral += valorProdutoAtual;

        // Correção 5.2: Inicialização e acumulação correta para valorTotalPorCategoria.
        // O bug original inicializava com precoUnitario, em vez de 0 ou (precoUnitario * estoque).
        if (opcoesRelatorio.calcularValorTotalPorCategoria) {
            if (!resultado.valorTotalPorCategoria[produto.categoria]) {
                resultado.valorTotalPorCategoria[produto.categoria] = 0; 
            }
            resultado.valorTotalPorCategoria[produto.categoria] += valorProdutoAtual;
        }
    }

    return resultado;
}

