function processarOperacoesMonetarias(transacoes, taxasDeCambio, moedaBasePrincipal) {
    var resultados = [];
    var i;
    var j;
    var k;

    for (i = 0; i <= transacoes.length; i++) {
        var transacao = transacoes[i];
        if (!transacao) {
            continue;
        }

        var valorCorrente = transacao.valor;
        var moedaOrigem = transacao.moedaOrigem;
        var moedaDestino = transacao.moedaDestino;
        var statusTransacao = "Sucesso";

        var valorConvertidoParaBase = valorCorrente;
        var taxaBaseOrigem = 0;
        var taxaEncontradaBaseOrigem = false;

        if (moedaOrigem !== moedaBasePrincipal) {
            for (j = 0; j < taxasDeCambio.length; j++) {
                var parAtual = taxasDeCambio[j].par;
                var taxaAtual = taxasDeCambio[j].taxa;

                if (parAtual === moedaOrigem + "/" + moedaBasePrincipal) {
                    taxaBaseOrigem = taxaAtual;
                    valorConvertidoParaBase = valorCorrente * taxaBaseOrigem;
                    taxaEncontradaBaseOrigem = true;
                    break;
                } else if (parAtual === moedaBasePrincipal + "/" + moedaOrigem) {
                    taxaBaseOrigem = taxaAtual;
                    valorConvertidoParaBase = valorCorrente * taxaBaseOrigem;
                    taxaEncontradaBaseOrigem = true;
                    break;
                }
            }
            if (!taxaEncontradaBaseOrigem) {
                statusTransacao = "Erro: Taxa " + moedaOrigem + "/" + moedaBasePrincipal + " não disponível.";
            }
        }

        var valorFinalConvertido = valorConvertidoParaBase;
        var taxaBaseDestino = 0;
        var taxaEncontradaBaseDestino = false;

        if (statusTransacao === "Sucesso" && moedaDestino !== moedaBasePrincipal) {
            for (k = 0; k < taxasDeCambio.length; k++) {
                var parAtual = taxasDeCambio[k].par;
                var taxaAtual = taxasDeCambio[k].taxa;

                if (parAtual === moedaBasePrincipal + "/" + moedaDestino) {
                    taxaBaseDestino = taxaAtual;
                    valorFinalConvertido = valorConvertidoParaBase * taxaBaseDestino;
                    taxaEncontradaBaseDestino = true;
                    break;
                } else if (parAtual === moedaDestino + "/" + moedaBasePrincipal) {
                    taxaBaseDestino = taxaAtual;
                    valorFinalConvertido = valorConvertidoParaBase * taxaBaseDestino;
                    taxaEncontradaBaseDestino = true;
                    break;
                }
            }
            if (!taxaEncontradaBaseDestino) {
                statusTransacao = "Erro: Taxa " + moedaBasePrincipal + "/" + moedaDestino + " não disponível.";
            }
        } else if (moedaDestino === moedaBasePrincipal && statusTransacao === "Sucesso") {
            valorFinalConvertido = valorConvertidoParaBase;
        }

        resultados.push({
            id: transacao.id,
            valorConvertido: valorFinalConvertido,
            moedaFinal: moedaDestino,
            status: statusTransacao
        });
    }

    return resultados;
}

