function processarOperacoesMonetarias(transacoes, taxasDeCambio, moedaBasePrincipal) {
    var resultados = [];
    var taxasLookup = {};
    var i;

    // Pré-processar taxasDeCambio para lookup eficiente O(1) em vez de O(N) por consulta
    for (i = 0; i < taxasDeCambio.length; i++) {
        taxasLookup[taxasDeCambio[i].par] = taxasDeCambio[i].taxa;
    }

    // Função auxiliar para obter a taxa, tratando direções de câmbio
    function obterTaxaDeCambio(moedaOrigem, moedaDestino) {
        // Tenta encontrar a taxa direta: Origem/Destino (e.g., BRL/USD)
        var parDireto = moedaOrigem + "/" + moedaDestino;
        if (taxasLookup.hasOwnProperty(parDireto)) {
            return taxasLookup[parDireto];
        }
        // Tenta encontrar a taxa inversa: Destino/Origem (e.g., USD/BRL para converter BRL para USD)
        var parInverso = moedaDestino + "/" + moedaOrigem;
        if (taxasLookup.hasOwnProperty(parInverso)) {
            return 1 / taxasLookup[parInverso];
        }
        return null; // Taxa não encontrada
    }

    for (i = 0; i < transacoes.length; i++) { // Correção: loop deve ir até < length
        var transacao = transacoes[i];
        var valorOriginal = transacao.valor;
        var moedaOrigem = transacao.moagemOrigem;
        var moedaDestino = transacao.moedaDestino;
        var valorFinal = valorOriginal;
        var status = "Sucesso";

        // Otimização: Se moeda de origem e destino são as mesmas, não há conversão
        if (moedaOrigem === moedaDestino) {
            resultados.push({
                id: transacao.id,
                valorConvertido: parseFloat(valorOriginal.toFixed(2)), // Arredondamento
                moedaFinal: moedaDestino,
                status: status
            });
            continue; // Próxima transação
        }

        var valorConvertidoParaBase = valorOriginal;

        // Passo 1: Converter para a moeda base principal, se necessário
        if (moedaOrigem !== moedaBasePrincipal) {
            var taxaParaBase = obterTaxaDeCambio(moedaOrigem, moedaBasePrincipal);
            if (taxaParaBase !== null) {
                valorConvertidoParaBase = valorOriginal * taxaParaBase;
            } else {
                status = "Erro: Taxa de " + moedaOrigem + " para " + moedaBasePrincipal + " não disponível.";
            }
        } // else: moedaOrigem já é a moedaBasePrincipal, não precisa de conversão

        // Passo 2: Converter da moeda base principal para a moeda destino, se necessário
        if (status === "Sucesso" && moedaDestino !== moedaBasePrincipal) {
            var taxaDaBase = obterTaxaDeCambio(moedaBasePrincipal, moedaDestino);
            if (taxaDaBase !== null) {
                valorFinal = valorConvertidoParaBase * taxaDaBase;
            } else {
                status = "Erro: Taxa de " + moedaBasePrincipal + " para " + moedaDestino + " não disponível.";
            }
        } else if (status === "Sucesso" && moedaDestino === moedaBasePrincipal) {
            // Se o destino é a moeda base, o valor final é o que foi convertido para a base
            valorFinal = valorConvertidoParaBase;
        }

        // Arredondamento do valor final para 2 casas decimais
        if (status === "Sucesso") {
             resultados.push({
                id: transacao.id,
                valorConvertido: parseFloat(valorFinal.toFixed(2)),
                moedaFinal: moedaDestino,
                status: status
            });
        } else {
             resultados.push({
                id: transacao.id,
                valorConvertido: parseFloat(valorOriginal.toFixed(2)), // Retorna o valor original em caso de erro
                moedaFinal: moedaDestino,
                status: status
            });
        }
    }

    return resultados;
}

