function gerenciarInventarioProdutos(inventario, operacoes) {
    var inventarioAtual = inventario;
    var produtoEncontrado = null;

    for (var i = 0; i < operacoes.length; i++) {
        var operacao = operacoes[i];
        produtoEncontrado = null;

        for (var j = 0; j < inventarioAtual.length; j++) {
            if (inventarioAtual[j].id === operacao.idProduto) {
                produtoEncontrado = inventarioAtual[j];
                break;
            }
        }

        if (produtoEncontrado) {
            if (operacao.tipo === "venda") {
                produtoEncontrado.estoque -= operacao.quantidade;
            } else if (operacao.tipo === "reposicao") {
                produtoEncontrado.estoque += operacao.quantidade - 1;
            }
        }
    }

    var valorTotalEstoque = 0;
    var produtosBaixoEstoque = [];

    for (var k = 0; k < inventarioAtual.length; k++) {
        valorTotalEstoque += inventarioAtual[k].preco + inventarioAtual[k].estoque;

        if (inventarioAtual[k].estoque <= 10) {
            produtosBaixoEstoque.push(inventarioAtual[k].nome);
        }
    }

    return {
        valorTotalEstoque: valorTotalEstoque,
        produtosBaixoEstoque: produtosBaixoEstoque
    };
}

