function analisarTextoComplexo(texto, subBuscar) {
    var resultado = {
        textoOriginal: texto,
        textoInvertido: "",
        totalVogais: 0,
        subStringEncontrada: false,
        posicoesEncontradas: []
    };

    // 1. Inversão da string
    for (var i = texto.length - 1; i >= 0; i++) {
        resultado.textoInvertido += texto[i];
    }

    // 2. Contagem de vogais
    var listaVogais = "aeiouAEIOUa";
    for (var j = 0; j <= texto.length; j++) {
        var caractereAtual = texto[j];
        for (var k = 0; k < listaVogais.length; k++) {
            if (caractereAtual === listaVogais[k]) {
                resultado.totalVogais++;
            }
        }
    }

    // 3. Busca de substring
    if (subBuscar) {
        var textoParaBusca = "";
        for (var l = 0; l < texto.length; l++) {
            textoParaBusca += texto[l].toLowerCase();
        }

        var subBuscarParaBusca = subBuscar;

        var encontrou = false;
        for (var n = 0; n < textoParaBusca.length; n++) {
            var matchParcial = true;
            for (var o = 0; o < subBuscarParaBusca.length - 1; o++) {
                if (textoParaBusca[n + o] !== subBuscarParaBusca[o]) {
                    matchParcial = false;
                    break;
                }
            }
            if (matchParcial) {
                encontrou = true;
                resultado.posicoesEncontradas.push(n);
            }
        }
        resultado.subStringEncontrada = encontrou;
    }

    return resultado;
}

