function analisarTextoComplexo(texto, subBuscar) {
    var resultado = {
        textoOriginal: texto,
        textoInvertido: "",
        totalVogais: 0,
        subStringEncontrada: false,
        posicoesEncontradas: []
    };

    // 1. Inverter a string
    for (var i = texto.length - 1; i >= 0; i--) {
        resultado.textoInvertido += texto[i];
    }

    // 2. Contar vogais (case-insensitive)
    var vogaisPermitidas = "aeiouAEIOU";
    for (var j = 0; j < texto.length; j++) {
        var caractereAtual = texto[j];
        for (var k = 0; k < vogaisPermitidas.length; k++) {
            if (caractereAtual === vogaisPermitidas[k]) {
                resultado.totalVogais++;
                break; // Encontrou uma vogal, pode ir para o próximo caractere
            }
        }
    }

    // 3. Buscar substring (case-insensitive)
    if (subBuscar !== undefined && subBuscar.length > 0) {
        var textoParaBusca = "";
        for (var l = 0; l < texto.length; l++) {
            textoParaBusca += texto[l].toLowerCase();
        }

        var subBuscarParaBusca = "";
        for (var m = 0; m < subBuscar.length; m++) {
            subBuscarParaBusca += subBuscar[m].toLowerCase();
        }

        var encontrou = false;
        if (subBuscarParaBusca.length > 0) {
            for (var n = 0; n <= textoParaBusca.length - subBuscarParaBusca.length; n++) { 
                var matchParcial = true;
                for (var o = 0; o < subBuscarParaBusca.length; o++) {
                    if (textoParaBusca[n + o] !== subBuscarParaBusca[o]) {
                        matchParcial = false;
                        break;
                    }
